import axios from 'axios'

const userActions = {
    signUpUser: (userData) => {
        return async (dispatch, getState) => {
            const res = await axios.post("http://localhost:4000/api/signUp", {userData})
            console.log(res);
            dispatch({type: "MESSAGE", payload:{
                view: true,
                message: res.data.message,
                success: res.data.success
            }})
        }
    },
    signInUser: (logedUser) => {
        return async (dispatch, getState) => {
            const res = await axios.post("http://localhost:4000/api/signIn", {logedUser})
            // dispatch({type: "MESSAGE", payload: console.log(res)})
            if(res.data.success) {
                localStorage.setItem('token', res.data.response.token)
                dispatch({
                    type: "USER",
                    payload: res.data.response.userData
                })
            }else{
                dispatch({
                    type: "MESSAGE",
                    payload: {
                        view: true,
                        message: res.data.message,
                        success: res.data.success
                    }
                })
            }
        }
    },
    signOutUser: (closeUser) => {
        return async (dispatch, getState) => {
            const res = await axios.post("http://localhost:4000/api/signOut", { closeUser })
            localStorage.removeItem('token')
            dispatch({ type: "USER", payload: null})
            return res
        }
    },
    verifyToken: (token) => {
        return async (dispatch, getState) => {
            await axios.get("http://localhost:4000/api/signInToken", {
                headers: {'Authorization': 'Bearer ' + token}})
                .then(user => {if (user.data.success) {
                    dispatch({ type: "USER", payload: user.data.response});
                    dispatch({ type: "MESSAGE",
                            payload: {view: true,
                            message: user.data.message,
                            success: user.data.success}
                        });
                }else {localStorage.removeItem('token')}
            }
            ).catch(error => {
                if (error.response.status === 401)
                dispatch({type: "MESSAGE",
                        payload: {view: true,
                                message: "Please signin again",
                                success: false}})
                localStorage.removeItem('token')
            })
        }
    }
}
export default userActions
